export const pcWidth = 800

export function isDisplayPC() {
  return window.innerWidth > pcWidth
}

export function getMp4url(url: string) {
  const DOMAIN = window.location.hostname
  if (DOMAIN.indexOf('cdn-') === -1) {
    return url.replace('cdn-', '')
  }
  return url
}

