export async function initSnapchatSDK(id: string, resultCb: any, errCb: any) {
  ;(window as any).snapKitInit = function () {
    /* Add your code here */
    attachSnapchat(id, resultCb, errCb)
  }
  ;(function (d, s, id) {
    let js: any
    let sjs: any = d.getElementsByTagName(s)[0]
    if (d.getElementById(id)) return
    js = d.createElement(s)
    js.id = id
    js.src = 'https://sdk.snapkit.com/js/v1/login.js'
    sjs.parentNode.insertBefore(js, sjs)
  })(document, 'script', 'loginkit-sdk')
}

export async function attachSnapchat(
  id: string,
  resultCb: (result: any) => void,
  errCb: (err: any) => void
) {
  let loginButtonIconId = id
  // Mount Login Button
  const snap = (window as any).snap
  snap.loginkit.mountButton(loginButtonIconId, {
    clientId: getPkgClientId(pkg).snapchat,
    redirectURI: window.location.href.split('?')[0],
    scopeList: ['user.display_name', 'user.bitmoji.avatar', 'user.external_id'],
    // scopeList: ['user.display_name'],
    handleResponseCallback() {
      snap.loginkit.fetchUserInfo().then(
        (result: any) => {
          resultCb(result)
        },
        (err: any) => {
          errCb(err)
        }
      )
    },
  })
}

export function refreshAccount(accountResp: any, source: string) {
  const { identities, user_info } = accountResp.data
  const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
  if (user_info) {
    const { session_key, uid, icon_verify } = user_info
    const o = { session_key, uid, icon_verify }
    const v = encodeURIComponent(JSON.stringify(o))
    if (getArgs('is_debug') === '2') return
    window.location.href = `${host}://sawaksa_login/?sawaksa_acount=${v}&source=${source}`
  }
}

export function cancelAccount(key: string) {
  const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
  if (getArgs('is_debug') === '2') return
  window.location.href = `${host}://unregister/?cancel_account_key=${key}`
}

export function unregisterRemind(data: any) {
  const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
  if (getArgs('is_debug') === '2') return
  window.location.href = `${host}://unregister_remind/?data=${encodeURIComponent(
    JSON.stringify(data)
  )}`
}

export function toFeedback() {
  reportEvent(Events.account_cancellation_verify_page_operation_result, {
    operation: '点击反馈入口',
  })
  const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
  window.location.href = `${host}://feedback`
}

export async function report(eventName: string, fields = {}) {
  if (getPlatform().isIPhone) {
    const json = fields
    const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
    window.location.href = `${host}://sawaksa_login_event/?eventName=${eventName}&jsonData=${btoa(
      encodeURIComponent(JSON.stringify(json))
    )}`
  } else {
    //
    let sa = getArgs('sa')
    if (sa) {
      sa = decodeURIComponent(sa)
      const isDebug = getArgs('is_debug')
      await initWebSensors(isDebug ? SensorSDKName.TEST : SensorSDKName.KSA, true, 'ajax', sa)
      reportWebSensors(eventName, fields)
    }
  }
}

export async function reportJustOutside(eventName: string, fields = {}) {
  console.warn('[report sa]', eventName, fields)
  const isDebug = getArgs('is_debug')
  await initWebSensors(isDebug ? SensorSDKName.TEST : SensorSDKName.KSA, true, 'ajax')
  reportWebSensors(eventName, fields)
}

export function getSub(access_token: string) {
  const arr = access_token.split('.')
  if (arr.length < 3) {
    return ''
  }
  try {
    const obj = arr[1]
    const subs = atob(obj)
    const o = JSON.parse(subs)
    const sub = o.sub
    return sub
  } catch (e) {
    return ''
  }
}

export function bindAccount(verify_token: string) {
  const host = isInLudoClient ? 'sawaludo' : 'sawaksa'
  window.location.href = `${host}://bind_unbind_update/?verify_token=${verify_token}`
}

