export function getArgs(k: string) {
  const v = getArgsFromUrl(k)
  if (v) {
    setStorage(k, v)
    return v
  } else {
    const _v = getStorage(k)
    return _v
  }
}

export const resolveThemeStyle = () => {
  const t = +getArgsFromUrlHash('type')
  console.warn('t', t)
  const clz = matchExpr(t, [
    [1, '-ksa'],
    [2, '-ludo'],
    [3, '-baloot'],
    [4, '-diwania'],
  ], () => '-ksa')
  if (clz) {
    document.getElementsByTagName('body')[0].classList.add(clz)
  }
}
